三步累乘 a×b×c。试试用 do-while 循环，先执行再判断。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int a, b, c;
    cin >> a >> b >> c;
    int ans = 1;
    int arr[3] = {a, b, c};
    int i = 0;
    do {
        ans *= arr[i];
        i++;
    } while (i < 3);
    cout << ans << endl;
    return 0;
}
```

先读 n，再用数组存每类的数量，用 for 循环累乘。注意 a_i ≤ 20、n ≤ 10，最大乘积 20¹⁰ ≈ 1e13，需用 long long。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, a[15];
    cin >> n;
    for (int i = 0; i < n; i++) cin >> a[i];
    long long ans = 1;
    for (int i = 0; i < n; i++) ans *= a[i];
    cout << ans << endl;
    return 0;
}
```

多组数据，每组用两层循环处理——外层遍历天数，内层累乘。但这里每组只有两个数，直接 a×b 即可。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int t;
    cin >> t;
    for (int i = 0; i < t; i++) {
        int a, b;
        cin >> a >> b;
        cout << a * b << endl;
    }
    return 0;
}
```

循环 n 次，每次累乘 k。跟课堂上的加法原理比一比：加法是"或"，乘法是"且"——这里每道题都要选，所以用乘法。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, k;
    cin >> n >> k;
    int ans = 1;
    for (int i = 0; i < n; i++) ans *= k;
    cout << ans << endl;
    return 0;
}
```

分别计算两种方案的总数再比较。需要两个数组、两次循环累乘、一个 if-else 判断。注意乘积可能超 int，需用 long long。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int a, b;
    int arrA[15], arrB[15];
    long long sumA = 1, sumB = 1;
    cin >> a;
    for (int i = 0; i < a; i++) { cin >> arrA[i]; sumA *= arrA[i]; }
    cin >> b;
    for (int i = 0; i < b; i++) { cin >> arrB[i]; sumB *= arrB[i]; }
    if (sumA > sumB) cout << "A" << endl;
    else if (sumA < sumB) cout << "B" << endl;
    else cout << "Same" << endl;
    return 0;
}
```
